ing? // JSON string\n  created_at       DateTime @default(now())\n  updated_at       DateTime @updatedAt\n}\n\nmodel Referral {\n  id                     String    @id @default(cuid())\n  referrer_email         String\n  referred_email         String    @unique\n  referred_name          String?\n  status                 String    @default(\"pending\")\n  referred_user_status   String    @default(\"invited\")\n  referrer_reward_status String    @default(\"no_reward\")\n  reward_details         String? // JSON string\n  completed_at           DateTime?\n  created_at             DateTime  @default(now())\n  updated_at             DateTime  @updatedAt\n}\n\nmodel ActivityLog {\n  id            String   @id @default(cuid())\n  user_email    String?\n  activity_type String\n  description   String\n  location_from String?\n  location_to   String?\n  is_public     Boolean  @default(false)\n  metadata      String? // JSON string\n  created_at    DateTime @default(now())\n  updated_at    DateTime @updatedAt\n}\n\nmodel PlatformSettings {\n  id                                     String   @id @default(cuid())\n  platform_name                          String   @default(\"Unswap\")\n  platform_status                        String   @default(\"pre_launch\")\n  founders_waiver_enabled                Boolean  @default(true)\n  required_verified_referrals_for_waiver Int      @default(5)\n  maintenance_mode                       Boolean  @default(false)\n  waitlist_enabled                       Boolean  @default(true)\n  max_properties_per_user                Int      @default(3)\n  early_bird_discount_pct                Float    @default(50)\n  early_bird_slots                       Int      @default(500)\n  trust_first_refund_days                Int      @default(30)\n  guest_points_per_swap_night            Int      @default(10)\n  institutional_email_domains            String? // JSON array string\n  public_settings                        String? // JSON string\n  created_at                             DateTime @default(now())\n  updated_at                             DateTime @updatedAt\n}\n\nmodel TypingStatus {\n  id              String   @id @default(cuid())\n  user_email      String\n  recipient_email String\n  is_typing       Boolean  @default(false)\n  last_updated    String?\n  created_at      DateTime @default(now())\n  updated_at      DateTime @updatedAt\n}\n\nmodel PinnedConversation {\n  id                String   @id @default(cuid())\n  user_email        String\n  conversation_with String\n  pinned_at         String?\n  created_at        DateTime @default(now())\n  updated_at        DateTime @updatedAt\n}\n\nmodel MessageReaction {\n  id         String   @id @default(cuid())\n  message_id String\n  user_email String\n  user_name  String?\n  reaction   String\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n}\n",
